package com.example.lessondesign.controller; import com.example.lessondesign.bean.School; import com.example.lessondesign.dao.SchoolDao; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.web.bind.annotation.*; @RestController @RequestMapping("/api/schools") public class SchoolController { @Autowired private SchoolDao schoolDao; @GetMapping("/name/{name}") public School getByName(@PathVariable String name){ return schoolDao.findByName(name); } }